"use client";

import { useEffect, useState } from "react";

type Props = {
  endTime: string | null;
  onComplete?: () => void;
  size?: "sm" | "md" | "lg";
};

export function CountdownTimer({ endTime, onComplete, size = "lg" }: Props) {
  const [secondsLeft, setSecondsLeft] = useState<number | null>(null);

  useEffect(() => {
    if (!endTime) return;

    const update = () => {
      const end = new Date(endTime).getTime();
      const now = Date.now();
      const diff = Math.max(0, Math.ceil((end - now) / 1000));
      setSecondsLeft(diff);
      if (diff === 0) onComplete?.();
    };

    update();
    const interval = setInterval(update, 1000);
    return () => clearInterval(interval);
  }, [endTime, onComplete]);

  if (secondsLeft === null) return null;

  const isCritical = secondsLeft <= 10;
  const sizeClass =
    size === "sm"
      ? "text-2xl w-16 h-16"
      : size === "md"
        ? "text-4xl w-24 h-24"
        : "text-6xl md:text-8xl w-32 h-32 md:w-40 md:h-40";

  return (
    <div
      className={`flex items-center justify-center rounded-2xl bg-[#1e1b4b] text-white font-bold ${sizeClass} ${
        isCritical ? "timer-critical bg-[#dc2626]" : ""
      }`}
    >
      {secondsLeft}
    </div>
  );
}
