"use client";

import { OPTION_COLORS } from "@/lib/colors";

type Props = {
  name: string;
  voteCount: number;
  address?: string;
  colorIndex: number;
  disabled?: boolean;
  selected?: boolean;
  onClick?: () => void;
};

export function OptionButton({
  name,
  voteCount,
  address,
  colorIndex,
  disabled,
  selected,
  onClick,
}: Props) {
  const color = OPTION_COLORS[colorIndex % OPTION_COLORS.length];
  const isVoting = !disabled && onClick;

  return (
    <button
      type="button"
      onClick={onClick}
      disabled={disabled}
      className={`
        option-hover w-full rounded-2xl border-4 px-6 py-5 text-left font-bold transition-all
        ${color.bg} ${color.hover} ${color.text} ${color.border}
        ${selected ? "ring-4 ring-white ring-offset-4 ring-offset-[#1e1b4b]" : ""}
        ${isVoting ? "cursor-pointer" : "cursor-default"}
        ${disabled ? "opacity-90" : ""}
      `}
    >
      <div className="flex flex-col gap-1">
        <div className="flex items-center justify-between gap-4">
          <span className="text-lg font-bold md:text-xl">{name}</span>
          <span className="rounded-full bg-white/25 px-3 py-1 text-sm">
            {voteCount} {voteCount === 1 ? "vote" : "votes"}
          </span>
        </div>
        {address && (
          <span className="text-sm font-normal opacity-90">{address}</span>
        )}
      </div>
    </button>
  );
}
