"use client";

import { useEffect, useRef, useState, useCallback } from "react";
import { io, Socket } from "socket.io-client";
import type { Room, Option } from "./api";

const WS_BASE =
  process.env.NEXT_PUBLIC_WS_URL ??
  process.env.NEXT_PUBLIC_API_URL ??
  "http://localhost:8000";

let socket: Socket | null = null;

export function getSocket(): Socket | null {
  return socket;
}

export function connectSocket(): Socket {
  if (socket?.connected) return socket;
  socket = io(WS_BASE, {
    transports: ["websocket", "polling"],
    reconnection: true,
    reconnectionAttempts: 5,
  });
  return socket;
}

export function disconnectSocket(): void {
  if (socket) {
    socket.disconnect();
    socket = null;
  }
}

export type RoomUpdatePayload = {
  room: Room;
  options?: Option[];
};

export function useRoomUpdates(
  roomCode: string | null,
  onUpdate: (payload: RoomUpdatePayload) => void
): { connected: boolean } {
  const [connected, setConnected] = useState(false);
  const onUpdateRef = useRef(onUpdate);
  onUpdateRef.current = onUpdate;

  useEffect(() => {
    if (!roomCode) return;

    const s = connectSocket();
    s.emit("join_room", roomCode);

    const handleConnect = () => setConnected(true);
    const handleDisconnect = () => setConnected(false);
    const handleRoomUpdate = (payload: RoomUpdatePayload) => {
      onUpdateRef.current(payload);
    };

    s.on("connect", handleConnect);
    s.on("disconnect", handleDisconnect);
    s.on("room_update", handleRoomUpdate);

    if (s.connected) setConnected(true);

    return () => {
      s.off("connect", handleConnect);
      s.off("disconnect", handleDisconnect);
      s.off("room_update", handleRoomUpdate);
      s.emit("leave_room", roomCode);
    };
  }, [roomCode]);

  return { connected };
}
