"use client";

import { useEffect, useState, useCallback } from "react";
import { useParams, useRouter } from "next/navigation";
import Link from "next/link";
import {
  getRoom,
  addOption,
  vote,
  startTimer,
  restartRoom,
  type Room,
  type Option,
} from "@/lib/api";
import { useRoomUpdates } from "@/lib/socket";
import { CountdownTimer } from "@/components/CountdownTimer";
import { OptionButton } from "@/components/OptionButton";
import { WinnerCard } from "@/components/WinnerCard";

export default function RoomPage() {
  const params = useParams();
  const router = useRouter();
  const code = (params?.code as string) ?? "";
  const [room, setRoom] = useState<Room | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");
  const [newOption, setNewOption] = useState("");
  const [addingOption, setAddingOption] = useState(false);
  const [startingVote, setStartingVote] = useState(false);
  const [locationError, setLocationError] = useState("");
  const [votedId, setVotedId] = useState<string | null>(null);

  const MAX_OPTIONS = 4;
  const userId = typeof window !== "undefined" ? localStorage.getItem("userId") : null;

  const fetchRoom = useCallback(async () => {
    if (!code) return;
    try {
      const r = await getRoom(code);
      setRoom(r);
      setError("");
    } catch (err) {
      setError(err instanceof Error ? err.message : "Room not found");
    } finally {
      setLoading(false);
    }
  }, [code]);

  useRoomUpdates(code, (payload) => {
    setRoom(payload.room);
  });

  useEffect(() => {
    fetchRoom();
  }, [fetchRoom]);

  useEffect(() => {
    if (!code || room?.status !== "voting") return;
    const interval = setInterval(fetchRoom, 2000);
    return () => clearInterval(interval);
  }, [code, room?.status, fetchRoom]);

  const isHost = userId === room?.hostId;

  const handleAddOption = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newOption.trim() || !userId) return;
    setAddingOption(true);
    try {
      await addOption(code, newOption.trim(), userId);
      setNewOption("");
      await fetchRoom();
    } catch (err) {
      setError(err instanceof Error ? err.message : "Failed to add");
    } finally {
      setAddingOption(false);
    }
  };

  const handleVote = async (optionId: string) => {
    if (!userId || votedId || room?.status !== "voting") return;
    try {
      await vote(code, optionId, userId);
      setVotedId(optionId);
      await fetchRoom();
    } catch (err) {
      setError(err instanceof Error ? err.message : "Vote failed");
    }
  };

  const startVotingWithLocation = async (lat: number, lng: number) => {
    if (!userId || !isHost) return;
    setStartingVote(true);
    setLocationError("");
    try {
      await startTimer(code, {
        userId,
        durationSeconds: 60,
        latitude: lat,
        longitude: lng,
      });
      await fetchRoom();
    } catch (err) {
      setLocationError(err instanceof Error ? err.message : "Failed to start");
    } finally {
      setStartingVote(false);
    }
  };

  const handleStartTimer = async () => {
    if (!userId || !isHost) return;
    setStartingVote(true);
    setLocationError("");

    const getLocation = (): Promise<{ lat: number; lng: number }> =>
      new Promise((resolve, reject) => {
        if (!navigator.geolocation) {
          reject(new Error("Geolocation not supported"));
          return;
        }
        navigator.geolocation.getCurrentPosition(
          (pos) =>
            resolve({
              lat: pos.coords.latitude,
              lng: pos.coords.longitude,
            }),
          (err) => reject(new Error(err.message ?? "Could not get location")),
          { enableHighAccuracy: true, timeout: 10000 }
        );
      });

    try {
      const { lat, lng } = await getLocation();
      await startVotingWithLocation(lat, lng);
    } catch (err) {
      const msg = err instanceof Error ? err.message : "Failed to start";
      setLocationError(msg);
    } finally {
      setStartingVote(false);
    }
  };

  const handleStartWithDemoLocation = () => {
    startVotingWithLocation(37.7749, -122.4194);
  };

  const handleRestart = async () => {
    if (!userId || !isHost) return;
    try {
      const r = await restartRoom(code, userId);
      setRoom(r);
      setVotedId(null);
    } catch (err) {
      setError(err instanceof Error ? err.message : "Failed to restart");
    }
  };

  if (loading) {
    return (
      <div className="flex min-h-screen items-center justify-center bg-[#f8fafc]">
        <div className="text-xl font-semibold text-[#1e1b4b]">Loading...</div>
      </div>
    );
  }

  if (error && !room) {
    return (
      <div className="flex min-h-screen flex-col items-center justify-center gap-4 bg-[#f8fafc] p-6">
        <p className="text-lg text-[#dc2626]">{error}</p>
        <Link
          href="/"
          className="rounded-xl bg-[#6d28d9] px-6 py-3 font-semibold text-white hover:bg-[#5b21b6]"
        >
          Go Home
        </Link>
      </div>
    );
  }

  if (!room) return null;

  const winner = (() => {
    if (room.status !== "finished" || room.options.length === 0) return null;
    const maxVotes = Math.max(...room.options.map((o) => o.voteCount));
    const tops = room.options.filter((o) => o.voteCount === maxVotes);
    return tops[Math.floor(Math.random() * tops.length)] ?? null;
  })();

  return (
    <div className="min-h-screen bg-[#f8fafc] p-4 md:p-6">
      <header className="mb-6 flex items-center justify-between">
        <Link
          href="/"
          className="text-[#6d28d9] font-semibold hover:underline"
        >
          ← Exit
        </Link>
        <div className="rounded-xl bg-[#1e1b4b] px-4 py-2">
          <span className="text-sm text-white/80">Room</span>
          <p className="text-xl font-bold tracking-widest text-white">{room.code}</p>
        </div>
      </header>

      {room.status === "waiting" && (
        <div className="mx-auto max-w-2xl space-y-6">
          <h2 className="text-center text-2xl font-bold text-[#1e1b4b]">
            Add up to 4 restaurant suggestions
          </h2>
          <p className="text-center text-sm text-[#64748b]">
            We&apos;ll find nearby restaurants matching these when voting starts.
          </p>
          <form
            onSubmit={handleAddOption}
            className="flex gap-2"
          >
            <input
              type="text"
              value={newOption}
              onChange={(e) => setNewOption(e.target.value)}
              placeholder="e.g. Sushi, Thai, Pizza"
              maxLength={64}
              disabled={room.options.length >= MAX_OPTIONS}
              className="flex-1 rounded-xl border-2 border-[#e2e8f0] px-4 py-3 focus:border-[#6d28d9] focus:outline-none disabled:bg-[#f1f5f9]"
            />
            <button
              type="submit"
              disabled={
                addingOption ||
                !newOption.trim() ||
                room.options.length >= MAX_OPTIONS
              }
              className="rounded-xl bg-[#6d28d9] px-6 py-3 font-bold text-white hover:bg-[#5b21b6] disabled:opacity-50"
            >
              Add
            </button>
          </form>
          {room.options.length >= MAX_OPTIONS && (
            <p className="text-center text-sm font-medium text-[#6d28d9]">
              Maximum 4 suggestions. Click Start voting when ready.
            </p>
          )}
          <div className="space-y-3">
            {room.options.length === 0 ? (
              <p className="py-8 text-center text-[#64748b]">
                No options yet. Add up to 4 suggestions above!
              </p>
            ) : (
              room.options.map((opt) => (
                <div
                  key={opt.id}
                  className="rounded-2xl border-2 border-[#e2e8f0] bg-white px-6 py-4 font-medium text-[#1e1b4b]"
                >
                  {opt.name}
                </div>
              ))
            )}
          </div>
          {isHost && (
            <>
              <button
                onClick={handleStartTimer}
                disabled={room.options.length < 2 || startingVote}
                className="mt-6 w-full rounded-2xl bg-[#059669] py-4 text-xl font-bold text-white shadow-lg hover:bg-[#047857] disabled:opacity-50 disabled:cursor-not-allowed"
              >
                {startingVote
                  ? "Finding restaurants nearby..."
                  : "Start voting (60 sec)"}
              </button>
              {locationError && (
                <div className="space-y-2">
                  <p className="text-center text-sm text-[#dc2626]">
                    {locationError} — Use localhost or enable location.
                  </p>
                  <button
                    type="button"
                    onClick={handleStartWithDemoLocation}
                    disabled={startingVote}
                    className="w-full rounded-xl border-2 border-dashed border-[#6d28d9] py-2 text-sm font-medium text-[#6d28d9] hover:bg-[#f3e8ff] disabled:opacity-50"
                  >
                    Continue with demo location
                  </button>
                </div>
              )}
            </>
          )}
          {!isHost && (
            <p className="text-center text-[#64748b]">
              Waiting for host to start voting...
            </p>
          )}
        </div>
      )}

      {room.status === "voting" && (
        <div className="mx-auto max-w-2xl space-y-6">
          <div className="flex flex-col items-center gap-4">
            <p className="text-lg font-semibold text-[#1e1b4b]">Time remaining</p>
            <CountdownTimer
              endTime={room.endTime}
              onComplete={fetchRoom}
              size="lg"
            />
          </div>
          <div className="space-y-4">
            {room.options.map((opt, i) => (
              <OptionButton
                key={opt.id}
                name={opt.name}
                voteCount={opt.voteCount}
                address={opt.address}
                colorIndex={i}
                disabled={!!votedId}
                selected={votedId === opt.id}
                onClick={() => handleVote(opt.id)}
              />
            ))}
          </div>
        </div>
      )}

      {room.status === "finished" && (
        <div className="mx-auto max-w-xl space-y-8">
          <h2 className="text-center text-2xl font-bold text-[#1e1b4b]">
            Results
          </h2>
          {winner && (
            <WinnerCard
              name={winner.name}
              voteCount={winner.voteCount}
              address={winner.address}
            />
          )}
          <div className="space-y-2">
            {room.options
              .sort((a, b) => b.voteCount - a.voteCount)
              .map((opt) => (
                <div
                  key={opt.id}
                  className="flex flex-col gap-0.5 rounded-xl border-2 border-[#e2e8f0] bg-white px-6 py-3"
                >
                  <div className="flex items-center justify-between">
                    <span className="font-medium">{opt.name}</span>
                    <span className="text-[#64748b]">{opt.voteCount} votes</span>
                  </div>
                  {opt.address && (
                    <span className="text-sm text-[#64748b]">{opt.address}</span>
                  )}
                </div>
              ))}
          </div>
          {isHost && (
            <button
              onClick={handleRestart}
              className="w-full rounded-2xl bg-[#6d28d9] py-4 text-xl font-bold text-white hover:bg-[#5b21b6]"
            >
              Restart session
            </button>
          )}
        </div>
      )}
    </div>
  );
}
