"use client";

type Props = {
  name: string;
  voteCount: number;
  address?: string;
};

export function WinnerCard({ name, voteCount, address }: Props) {
  return (
    <div className="winner-reveal rounded-3xl border-4 border-[#6d28d9] bg-gradient-to-br from-[#6d28d9] to-[#7c3aed] p-8 text-white shadow-2xl">
      <p className="mb-2 text-sm font-semibold uppercase tracking-wider text-white/80">
        Winner!
      </p>
      <h2 className="text-3xl font-bold md:text-4xl">{name}</h2>
      {address && (
        <p className="mt-1 text-base text-white/90">{address}</p>
      )}
      <p className="mt-2 text-lg text-white/90">{voteCount} votes</p>
    </div>
  );
}
